source_sections.text:
{
  "day": "1",
  "heading": "Drive from Kathgodam to Gogina",
  "sub_heading": "Drive distance: 235 km | Duration: 10-11 hours | Pick-up point for Indiahikes trekkers: Kathgodam Railway Station | Location of Indiahikes basecamp: Gogina",
  "details": "Transport will be organised from Kathgodam Railway Station at 5:30 AM. The cost is Rs.1800/- (additional 5% GST) per trekker (one-way). These are non-AC vehicles. Please pre-book your transport through the dashboard before your trek."
}

{
  "day": "2",
  "heading": "Trek from Gogina to Namik Campsite",
  "sub_heading": "Trek distance: 6.5 km | Duration: 6 hours | Altitude loss and gain: 6,415 ft to 5,938 ft to 7,390 ft",
  "details": "An Easy-moderate day with sharp descent from Gogina to Ramganga river followed by a steep ascent through the forests to reach Namik village."
}

{
  "day": "3",
  "heading": "Trek from Namik Campite to Bajimanian Kharak",
  "sub_heading": "Trek distance: 5.4 km | Duration: 6-7 hours | Altitude gain: 7,390 ft to 9,690 ft",
  "details": "Another day which is of Easy-Moderate. Gradual ascent through some lovely forest sections and the Kharaks or clearings through the day"
}

{
  "day": "4",
  "heading": "Trek from Baji Kharak to Thal Tok",
  "sub_heading": "Trek distance: 5 km | Duration: 6-7 hours | Altitude gain: 9,690 ft to 11,130 ft",
  "details": "Gradual ascent on the trail followed by a ledge walk towards the meadows. The climb picks up from the meadow towards the moraine region of Thal Tok."
}

{
  "day": "5",
  "heading": "Trek from Thal Tok to Parava Thor via Ranthan Top.",
  "sub_heading": "Trek distance: 10 km | Duration: 11-12 hours | Altitude gain and loss: 11,130 ft to 9,000 ft via 12,887 ft",
  "details": "A day with Rocky and bouldery terrain with steep ascent until Ranthan Top. Steep descent back to Thal Tok, the ledge traverse, and then a gradual descent till you reach Parava Thor."
}

{
  "day": "6",
  "heading": "Trek from Parava Thor to Gogina",
  "sub_heading": "Trek distance: 9.5 km | Duration: 5-6 hours | Altitude loss: 9,000 ft to 6,415 ft",
  "details": "From Parava Thor, trek to Namik. From here, it's the reverse of a steep descent until Ramganga and then ascent to Gogina"
}

{
  "day": "7",
  "heading": "Drive from Gogina to Kathgodam",
  "sub_heading": "Drive distance: 235 km | Duration: 10-11 hours",
  "details": "You are expected to reach Kathgodam Railway Station by 7.00 pm. The cost is Rs.1800/- (additional 5% GST) per trekker (one-way). Please pre-book your transport through the dashboard before your trek.\nPlease note: The distance between campsites may vary by 100 meters depending on the weather conditions and the route you take. The altitude may also vary by 100 feet for similar reasons."
}
